<template>
  <div>
    <el-dialog v-bind="$attrs" v-on="$listeners" :visible.sync="showDialog" @open="onOpen" @close="onClose" title="修改学生简历信息">
      <el-row :gutter="15">
        <el-form ref="elForm" :model="data" :rules="rules" size="medium" label-width="80px">
          <el-col :span="12">
            <el-form-item label="简历名称" prop="rtitle">
              <el-input v-model="data.rtitle" placeholder="请输入简历名称" clearable :style="{width: '100%'}">
              </el-input>
            </el-form-item>
            <el-form-item label="期望工作" prop="rwantworks">
              <el-input v-model="data.rwantworks" placeholder="请输入期望工作" clearable :style="{width: '100%'}">
              </el-input>
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="期望薪资" prop="rwages">
              <el-input v-model="data.rwages" placeholder="请输入期望薪资" clearable :style="{width: '100%'}">
              </el-input>
            </el-form-item>
            <el-form-item label="简历类型" prop="scollege">
              <select v-model="data.tname" class="form-control" :style="{width: '100%', height: '38px'}">
                <option v-for="item in drugs" :key="item.tname" :label="item.tname"
                        :value="item.tname"></option>
              </select>
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="教育经历" prop="redus">
              <el-input type="textarea" v-model="data.redus" placeholder="请输入教育经历" clearable
                        :autosize="{ minRows: 5, maxRows: 10}" :style="{width: '100%'}">
              </el-input>
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="工作经历" prop="rworks">
              <el-input type="textarea" v-model="data.rworks" placeholder="请输入工作经历" clearable
                        :autosize="{ minRows: 5, maxRows: 10}" :style="{width: '100%'}">
              </el-input>
            </el-form-item>
          </el-col>
        </el-form>
      </el-row>
      <div slot="footer">
        <el-button @click="close">取消</el-button>
        <el-button type="primary" @click="handelConfirm">确定</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>

  import ImageCropper from '../../components/ImageCropper';
  import PanThumb from '../../components/PanThumb';
  import { updateResumes } from '../../api/resumes';
  import { getTypes } from '../../api/types';

  export default {
    name: 'ResumesEdit',
    components: { ImageCropper, PanThumb },
    props:{
      addOrUpdateVisible:{
        type: Boolean,
        default: false
      }
    },
    data() {
      return {
        drugs:[],
        data: {
          rworks: '',
          redus: '',
          rwantworks: '',
          rwages: '',
          rtitle:'',
          tname:'',
          id:''
        },
        showDialog:false,
        rules: {
          rworks: [{
            required: true,
            mescstaffnums: '请输入工作经历',
            trigger: 'blur'
          }],
          rwage: [{
            required: true,
            mescstaffnums: '请输入期望工资',
            trigger: 'blur'
          }],
          redus: [{
            required: true,
            mescstaffnums: '请输入教育经历',
            trigger: 'blur'
          }],
          rwantworks: [{
            required: true,
            mescstaffnums: '请输入期望工作',
            trigger: 'blur'
          }],
          rtitle: [{
            required: true,
            mescstaffnums: '请输入简历名称',
            trigger: 'blur'
          }],
          tname: [{
            required: true,
            mescstaffnums: '请选择简历类型',
            trigger: 'blur'
          }]
        }
      };
    },
    computed: {},
    watch: {
      addOrUpdateVisible(oldVal,newVal){
        this.showDialog = this.addOrUpdateVisible;
      }
    },
    created() {
    },
    mounted() {
      this.getTypes();
    },
    methods: {
      async getTypes(){
        const { data } = await getTypes();
        this.drugs = data.data.records;
      },
      onOpen() {
      },
      dataInit(data){
        if(data){
          this.data = data;
        }
      },
      onClose() {
        this.$refs.elForm.resetFields();
        this.$emit('changeShow', 'false');
      },
      close() {
        this.$emit('changeShow', 'false');
      },
      handelConfirm() {
        this.$refs.elForm.validate((valid) => {
          if (!valid) return;
          this.updateData();
        });
      },
      async updateData(){
        var that = this;
        const { data:res } = await updateResumes(this.data);
        if(res.code == 200){
          this.$notify.success({
            title:'操作成功',
            message: '修改成功'
          });
          this.$emit('changeShow','false');
          this.data = {};
          this.$emit('getDataList');
        }else{
          return this.$message.error('修改失败:'+res.message);
        }
      }
    }
  };

</script>
<style>
  .el-upload__tip {
    line-height: 1.2;
  }

</style>
